function getEthProvider() {
  if (window.ethereum) return window.ethereum;
  throw new Error("No Ethereum provider found. Install MetaMask or another wallet.");
}

async function connectWallet() {
  try {
    const injected = getEthProvider();
    state.provider = new ethers.BrowserProvider(injected);
    await injected.request({ method: "eth_requestAccounts" });
    state.signer = await state.provider.getSigner();
    state.account = await state.signer.getAddress();
    const network = await state.provider.getNetwork();
    state.chainId = network.chainId.toString();

    if (injected.on) {
      injected.on("accountsChanged", handleAccountsChanged);
      injected.on("chainChanged", handleChainChanged);
      injected.on("disconnect", handleDisconnect);
    }

    updateWalletUI();
    setStatus("Connected");
    appendLog(`Connected: ${state.account}`);
  } catch (err) {
    setStatus("Connection failed");
    appendLog(err.message || String(err), "error");
  }
}

function updateWalletUI() {
  if ($("account")) $("account").textContent = state.account || "-";
  if ($("chainId")) $("chainId").textContent = state.chainId || "-";
  if ($("lastTxHash")) $("lastTxHash").textContent = state.lastTxHash || "-";
}

function handleAccountsChanged(accounts) {
  state.account = accounts && accounts.length ? accounts[0] : null;
  updateWalletUI();
  appendLog(`Accounts changed: ${state.account || "none"}`);
}

function handleChainChanged(chainId) {
  state.chainId = typeof chainId === "string" ? parseInt(chainId, 16).toString() : String(chainId);
  updateWalletUI();
  appendLog(`Chain changed: ${state.chainId}`);
}

function handleDisconnect() {
  appendLog("Wallet disconnected");
  resetApp();
}

function resetApp() {
  state.provider = null;
  state.signer = null;
  state.account = null;
  state.chainId = null;
  state.lastTxHash = null;
  updateWalletUI();
  setStatus("Disconnected");
  if ($("txPreview")) $("txPreview").textContent = "{}";
  appendLog("State reset");
}

function readForm() {
  const contractAddress = $("contractAddress")?.value.trim();
  const abiText = $("contractAbi")?.value.trim();
  const functionName = $("functionName")?.value.trim();
  const argsText = $("functionArgs")?.value.trim();
  const valueText = $("txValue")?.value.trim();

  if (!contractAddress) throw new Error("Contract address is required.");
  if (!abiText) throw new Error("ABI JSON is required.");
  if (!functionName) throw new Error("Function name is required.");

  let abi;
  let args = [];
  try {
    abi = JSON.parse(abiText);
  } catch {
    throw new Error("Invalid ABI JSON.");
  }

  if (argsText) {
    try {
      args = JSON.parse(argsText);
      if (!Array.isArray(args)) throw new Error();
    } catch {
      throw new Error("Function arguments must be a valid JSON array.");
    }
  }

  const value = valueText ? ethers.parseEther(String(Number(valueText) / 1e18 || valueText)) : 0n;
  return { contractAddress, abi, functionName, args, value };
}

function buildContract() {
  if (!state.signer) throw new Error("Connect wallet first.");
  const { contractAddress, abi } = readForm();
  return new ethers.Contract(contractAddress, abi, state.signer);
}

async function populateTransaction() {
  try {
    const { contractAddress, abi, functionName, args, value } = readForm();
    if (!state.signer) throw new Error("Connect wallet first.");
    const contract = new ethers.Contract(contractAddress, abi, state.signer);
    const txRequest = await contract[functionName].populateTransaction(...args);
    const preview = {
      to: contractAddress,
      data: txRequest.data || null,
      value: value.toString(),
      from: state.account,
      functionName,
      args,
    };
    if (value > 0n) txRequest.value = value;
    if ($("txPreview")) $("txPreview").textContent = JSON.stringify(preview, null, 2);
    appendLog(`Populated transaction for ${functionName}`);
    return txRequest;
  } catch (err) {
    appendLog(err.message || String(err), "error");
    throw err;
  }
}

async function sendTransaction() {
  try {
    const { contractAddress, abi, functionName, args, value } = readForm();
    if (!state.signer) throw new Error("Connect wallet first.");

    const contract = new ethers.Contract(contractAddress, abi, state.signer);
    const overrides = {};
    if (value > 0n) overrides.value = value;

    const tx = await contract[functionName](...args, overrides);
    state.lastTxHash = tx.hash;
    updateWalletUI();

    if ($("txPreview")) {
      $("txPreview").textContent = JSON.stringify(
        {
          hash: tx.hash,
          to: tx.to,
          from: tx.from,
          nonce: tx.nonce,
          data: tx.data,
          value: tx.value ? tx.value.toString() : undefined,
        },
        null,
        2
      );
    }

    setStatus("Transaction sent");
    appendLog(`TX sent: ${tx.hash}`);

    const receipt = await tx.wait();
    appendLog(`TX confirmed in block ${receipt.blockNumber}`, "success");
    setStatus("Transaction confirmed");
    return receipt;
  } catch (err) {
    setStatus("Transaction failed");
    appendLog(err.message || String(err), "error");
    throw err;
  }
}

async function readContractCall() {
  try {
    const { contractAddress, abi, functionName, args } = readForm();
    if (!state.provider) throw new Error("Connect wallet first.");
    const contract = new ethers.Contract(contractAddress, abi, state.provider);
    const result = await contract[functionName](...args);
    if ($("txPreview")) {
      $("txPreview").textContent = JSON.stringify(
        Array.isArray(result) ? result.map((v) => (ethers.isBytesLike(v) ? ethers.hexlify(v) : v?.toString?.() ?? v)) : result,
        null,
        2
      );
    }
    appendLog(`Read call executed: ${functionName}`);
    return result;
  } catch (err) {
    appendLog(err.message || String(err), "error");
    throw err;
  }
}

